import base64
import zlib
from urllib.parse import urlencode
import requests

def build_saml_request(destination_url, user_info):
    saml_request_template = '''
    <samlp:AuthnRequest
        xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="id123"
        Version="2.0"
        IssueInstant="2023-01-01T12:00:00Z"
        Destination="{destination}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <samlp:NameIDPolicy 
            Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
            AllowCreate="true"/>
    </samlp:AuthnRequest>
    '''
    
    saml_request = saml_request_template.format(
        destination=destination_url,
        issuer=user_info['issuer']
    )
    compressed_request = zlib.compress(saml_request.encode('utf-8'), -1)[2:-4]
    b64_encoded_request = base64.b64encode(compressed_request).decode('utf-8')
    return b64_encoded_request

def send_saml_request(destination_url, user_info):
    saml_request = build_saml_request(destination_url, user_info)
    data = {
        'SAMLRequest': saml_request
    }
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded'
    }
    response = requests.post(destination_url, data=urlencode(data), headers=headers)
    return response

